// Normalize NotebookLM / Google Docs output
const body = $input.first().json.body;
const content = body.content || body.text || body.research || '';

// Strip common NotebookLM artifacts
const normalized = content
  .replace(/\[?\d+\]?(?=\s)/g, '')           // footnote markers like [1] or 1
  .replace(/Source:?\s*\d+/gi, '')             // "Source: 3" refs
  .replace(/\n{3,}/g, '\n\n')                 // collapse excessive newlines
  .replace(/^\s+|\s+$/gm, '')                 // trim each line
  .replace(/[\u200B-\u200D\uFEFF]/g, '')      // zero-width chars
  .trim();

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    normalized_content: normalized,
    char_count: normalized.length,
    word_count: normalized.split(/\s+/).length,
    intake_timestamp: new Date().toISOString(),
    intake_date: today,
    source: body.source || 'notebooklm_manual'
  }
}];

// Safe parse Claude extraction response
const data = $input.first().json;

// Check for API errors
if (data.error || !data.content || !data.content[0]) {
  return [{
    json: {
      error: 'claude_api_error',
      message: data.error?.message || 'No content in response',
      signals: []
    }
  }];
}

const raw = data.content[0].text;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);

  // Validate structure
  if (!Array.isArray(parsed.signals)) {
    return [{ json: { error: 'invalid_structure', raw, signals: [] } }];
  }

  return [{ json: parsed }];
} catch(e) {
  return [{ json: { error: 'parse_failed', message: e.message, raw, signals: [] } }];
}

// Safe parse Claude scoring response
const data = $input.first().json;

if (data.error || !data.content || !data.content[0]) {
  // Pass through original signals unscored rather than losing them
  const originalSignals = $('Parse Extraction').first().json.signals || [];
  return [{
    json: {
      error: 'scoring_failed',
      scored_signals: originalSignals.map(s => ({
        ...s,
        conviction: 3,  // default base score
        wheel_eligible: false,
        suggested_strategy: 'watch',
        premium_environment: 'fair',
        scoring_error: true
      }))
    }
  }];
}

const raw = data.content[0].text;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);

  if (!Array.isArray(parsed.scored_signals)) {
    throw new Error('scored_signals not an array');
  }

  return [{ json: parsed }];
} catch(e) {
  // Fallback: return unscored signals
  const originalSignals = $('Parse Extraction').first().json.signals || [];
  return [{
    json: {
      error: 'score_parse_failed',
      scored_signals: originalSignals.map(s => ({
        ...s,
        conviction: 3,
        wheel_eligible: false,
        suggested_strategy: 'watch',
        premium_environment: 'fair',
        scoring_error: true
      }))
    }
  }];
}

// Build ticker list for dedup query
const scored = $input.first().json.scored_signals || [];
const tickers = [...new Set(scored.map(s => s.ticker?.toUpperCase()).filter(Boolean))];

return [{
  json: {
    scored_signals: scored,
    tickers: tickers,
    ticker_filter: tickers.join(',')
  }
}];

// Merge scored signals with dedup results
const scoredData = $('Prep Dedup Query').first().json;
const scored = scoredData.scored_signals || [];
const existing = $('Dedup Check — Supabase').first().json;

// Handle Supabase returning single object vs array
const existingArr = Array.isArray(existing) ? existing : (existing ? [existing] : []);
const existingKeys = new Set(
  existingArr.map(e => (e.ticker + '|' + e.thesis).toLowerCase())
);

const now = new Date().toISOString();

const validated = scored
  .filter(s => {
    // Required fields
    if (!s.ticker || !s.direction || !s.thesis) return false;
    if (typeof s.conviction !== 'number' || s.conviction < 1 || s.conviction > 10) return false;
    return true;
  })
  .map(s => {
    const key = (s.ticker + '|' + s.thesis).toLowerCase();
    return {
      ticker: s.ticker.toUpperCase().trim(),
      direction: s.direction,
      thesis: s.thesis.slice(0, 200),
      source_type: s.source_type || 'fundamental',
      catalysts: JSON.stringify(s.catalysts || []),
      risk_factors: JSON.stringify(s.risk_factors || []),
      sector: s.sector || 'Unknown',
      congressional_refs: JSON.stringify(s.congressional_refs || []),
      timeframe: s.timeframe || 'medium',
      conviction: Math.min(10, Math.max(1, Math.round(s.conviction))),
      wheel_eligible: s.wheel_eligible || false,
      suggested_strategy: s.suggested_strategy || 'watch',
      premium_environment: s.premium_environment || 'fair',
      status: 'active',
      updated_at: now,
      _is_update: existingKeys.has(key)
    };
  });

const highConviction = validated.filter(s => s.conviction >= 7);

return [{
  json: {
    signals: validated,
    total: validated.length,
    new_count: validated.filter(s => !s._is_update).length,
    update_count: validated.filter(s => s._is_update).length,
    high_conviction: highConviction,
    high_conviction_count: highConviction.length,
    tickers_processed: [...new Set(validated.map(s => s.ticker))]
  }
}];

