// Build final webhook response
const mergeData = $('Merge & Validate').first().json;

return [{
  json: {
    status: 'processed',
    signals_extracted: mergeData.total,
    signals_new: mergeData.new_count,
    signals_updated: mergeData.update_count,
    high_conviction: (mergeData.high_conviction || []).map(s => ({
      ticker: s.ticker,
      conviction: s.conviction,
      direction: s.direction,
      suggested_strategy: s.suggested_strategy,
      wheel_eligible: s.wheel_eligible,
      thesis: s.thesis
    })),
    tickers_processed: mergeData.tickers_processed,
    processed_at: new Date().toISOString()
  }
}];

// No signals found or extraction error — still archive and log
return [{
  json: {
    status: 'processed',
    signals_extracted: 0,
    signals_new: 0,
    signals_updated: 0,
    high_conviction: [],
    tickers_processed: [],
    note: $json.error ? 'Extraction error: ' + $json.error : 'No actionable signals found in research brief',
    processed_at: new Date().toISOString()
  }
}];

// Rejected payload — too short or missing
return [{
  json: {
    status: 'rejected',
    error: 'Payload content is missing or too short (minimum 50 characters)',
    signals_extracted: 0,
    processed_at: new Date().toISOString()
  }
}];
